'use client';

import * as React from 'react';

import { cn } from '@/lib/utils';
import {
  AddIcon,
  CheckIcon,
  ChevronDownIcon,
  ChevronRightIcon,
  CloseIcon,
  CopyIcon,
  EditIcon,
  FilterIcon,
  RefreshIcon,
  SearchIcon,
  SettingsIcon,
  TrashIcon,
} from '@/components/jetbrains-ui/icons';
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuSub,
  ContextMenuSubContent,
  ContextMenuSubTrigger,
  ContextMenuTrigger,
} from '@/components/jetbrains-ui/context-menu';
import './index.css';

const treeContextMenuIcons = {
  add: AddIcon,
  check: CheckIcon,
  close: CloseIcon,
  copy: CopyIcon,
  delete: TrashIcon,
  edit: EditIcon,
  filter: FilterIcon,
  refresh: RefreshIcon,
  search: SearchIcon,
  settings: SettingsIcon,
  trash: TrashIcon,
} as const;

export type TreeContextMenuIconName = keyof typeof treeContextMenuIcons;

export interface TreeContextMenuNode {
  id: string;
  value: string;
  label: string;
  data: Pick<TreeItemProps, 'label' | 'icon' | 'endContent' | 'disabled'>;
  disabled: boolean;
  expanded: boolean;
  hasChildren: boolean;
  level: number;
  selected: boolean;
}

export interface TreeContextMenuItem {
  key: string;
  label?: React.ReactNode;
  text?: React.ReactNode;
  disabled?: boolean;
  separator?: boolean;
  separatorAfter?: boolean;
  iconName?: TreeContextMenuIconName;
  variant?: 'default' | 'destructive';
  onSelect?: (node: TreeContextMenuNode) => void;
  children?: TreeContextMenuItem[];
  items?: TreeContextMenuItem[];
}

type RegisteredTreeItem = TreeContextMenuNode;

type TreeContextValue = {
  selectedId: string | null;
  setSelectedId: (nextId: string) => void;
  expandedIds: Set<string>;
  toggleExpanded: (id: string, expanded?: boolean) => void;
  indent: number;
  registerItem: (item: RegisteredTreeItem) => void;
  unregisterItem: (id: string) => void;
};

interface TreeProps
  extends Omit<React.ComponentPropsWithoutRef<'ul'>, 'contextMenu'> {
  selectedId?: string | null;
  defaultSelectedId?: string | null;
  onSelectedIdChange?: (id: string) => void;
  expandedIds?: string[];
  defaultExpandedIds?: string[];
  onExpandedIdsChange?: (ids: string[]) => void;
  indent?: number;
  contextMenu?: (
    node: TreeContextMenuNode,
  ) => TreeContextMenuItem[] | null | undefined;
}

interface TreeItemProps
  extends Omit<React.ComponentProps<'li'>, 'children' | 'id'> {
  value: string;
  label: React.ReactNode;
  icon?: React.ReactNode;
  endContent?: React.ReactNode;
  disabled?: boolean;
  children?: React.ReactNode;
}

const TreeContext = React.createContext<TreeContextValue | null>(null);
const TreeLevelContext = React.createContext(1);
const GROUP_COLLAPSE_DURATION = 180;
const treeRootClassName =
  'jb-tree block w-[244px] max-w-full box-border py-2 text-[13px] leading-4 font-medium';
const treeListClassName = 'm-0 list-none p-0';
const treeItemClassName = 'jb-tree-item m-0 list-none p-0';
const treeGroupClassName = 'jb-tree-group m-0 list-none p-0';
const treeItemButtonClassName =
  'jb-tree-item-button relative flex h-6 w-full min-w-0 cursor-default items-center gap-0.5 pr-4 select-none outline-none transition-[color,background-color,box-shadow] duration-150 ease-in-out';
const treeDisclosureClassName =
  'jb-tree-item-disclosure inline-flex size-4 shrink-0 items-center justify-center';
const treeDisclosurePlaceholderClassName =
  'jb-tree-item-disclosure-placeholder inline-flex size-4 shrink-0 items-center justify-center';
const treeItemContentClassName =
  'jb-tree-item-content inline-flex h-5 min-w-0 flex-1 items-center gap-1.5';
const treeItemIconClassName =
  'jb-tree-item-icon inline-flex size-4 shrink-0 items-center justify-center';
const treeItemLabelClassName =
  'jb-tree-item-label min-w-0 overflow-hidden text-ellipsis whitespace-nowrap';
const treeItemEndClassName =
  'jb-tree-item-end ml-auto pr-0.5 text-[13px] leading-4 font-medium';

function useTreeContext() {
  const context = React.useContext(TreeContext);

  if (!context) {
    throw new Error('Tree components must be used within <Tree>.');
  }

  return context;
}

function mergeExpandedIds(
  current: string[],
  id: string,
  expanded: boolean,
): string[] {
  const next = new Set(current);

  if (expanded) {
    next.add(id);
  } else {
    next.delete(id);
  }

  return Array.from(next);
}

function getTreeItemLabel(label: React.ReactNode, fallback: string) {
  if (typeof label === 'string') {
    return label;
  }

  return fallback;
}

function resolveContextMenuLabel(item: TreeContextMenuItem) {
  return item.label ?? item.text ?? item.key;
}

function resolveContextMenuChildren(item: TreeContextMenuItem) {
  return item.children ?? item.items ?? [];
}

function resolveContextMenuSeparator(item: TreeContextMenuItem) {
  return item.separatorAfter ?? item.separator ?? false;
}

function TreeContextMenuEntries({
  items,
  node,
}: {
  items: TreeContextMenuItem[];
  node: TreeContextMenuNode;
}) {
  return (
    <>
      {items.map((item) => {
        const label = resolveContextMenuLabel(item);
        const childItems = resolveContextMenuChildren(item);
        const IconComponent = item.iconName
          ? treeContextMenuIcons[item.iconName]
          : null;
        const entry = childItems.length ? (
          <ContextMenuSub key={item.key}>
            <ContextMenuSubTrigger disabled={item.disabled}>
              {IconComponent ? (
                <IconComponent
                  aria-hidden="true"
                  className="size-4"
                  size={16}
                />
              ) : null}
              <span className="truncate">{label}</span>
            </ContextMenuSubTrigger>
            <ContextMenuSubContent>
              <TreeContextMenuEntries items={childItems} node={node} />
            </ContextMenuSubContent>
          </ContextMenuSub>
        ) : (
          <ContextMenuItem
            key={item.key}
            disabled={item.disabled}
            variant={item.variant}
            onSelect={() => item.onSelect?.(node)}
          >
            {IconComponent ? (
              <IconComponent aria-hidden="true" className="size-4" size={16} />
            ) : null}
            <span className="truncate">{label}</span>
          </ContextMenuItem>
        );

        if (!resolveContextMenuSeparator(item)) {
          return entry;
        }

        return (
          <React.Fragment key={`${item.key}-group`}>
            {entry}
            <ContextMenuSeparator />
          </React.Fragment>
        );
      })}
    </>
  );
}

function Tree({
  children,
  className,
  style,
  selectedId,
  defaultSelectedId = null,
  onSelectedIdChange,
  expandedIds,
  defaultExpandedIds = [],
  onExpandedIdsChange,
  indent = 16,
  contextMenu,
  onContextMenuCapture,
  ...props
}: TreeProps) {
  const [uncontrolledSelectedId, setUncontrolledSelectedId] = React.useState<
    string | null
  >(defaultSelectedId);
  const [uncontrolledExpandedIds, setUncontrolledExpandedIds] =
    React.useState<string[]>(defaultExpandedIds);
  const [contextMenuNode, setContextMenuNode] =
    React.useState<TreeContextMenuNode | null>(null);
  const [contextMenuItems, setContextMenuItems] = React.useState<
    TreeContextMenuItem[]
  >([]);
  const itemRegistryRef = React.useRef(new Map<string, RegisteredTreeItem>());

  const resolvedSelectedId =
    selectedId !== undefined ? selectedId : uncontrolledSelectedId;
  const resolvedExpandedIds =
    expandedIds !== undefined ? expandedIds : uncontrolledExpandedIds;

  const setSelectedId = React.useCallback(
    (nextId: string) => {
      if (selectedId === undefined) {
        setUncontrolledSelectedId(nextId);
      }

      onSelectedIdChange?.(nextId);
    },
    [onSelectedIdChange, selectedId],
  );

  const setExpandedIds = React.useCallback(
    (nextIds: string[]) => {
      if (expandedIds === undefined) {
        setUncontrolledExpandedIds(nextIds);
      }

      onExpandedIdsChange?.(nextIds);
    },
    [expandedIds, onExpandedIdsChange],
  );

  const toggleExpanded = React.useCallback(
    (id: string, expanded?: boolean) => {
      const isExpanded = resolvedExpandedIds.includes(id);
      const nextExpanded = expanded ?? !isExpanded;
      const nextIds = mergeExpandedIds(resolvedExpandedIds, id, nextExpanded);

      setExpandedIds(nextIds);
    },
    [resolvedExpandedIds, setExpandedIds],
  );

  const registerItem = React.useCallback((item: RegisteredTreeItem) => {
    itemRegistryRef.current.set(item.id, item);
  }, []);

  const unregisterItem = React.useCallback((id: string) => {
    itemRegistryRef.current.delete(id);
  }, []);

  const clearContextMenuState = React.useCallback(() => {
    setContextMenuNode(null);
    setContextMenuItems([]);
  }, []);

  const contextValue = React.useMemo<TreeContextValue>(
    () => ({
      selectedId: resolvedSelectedId,
      setSelectedId,
      expandedIds: new Set(resolvedExpandedIds),
      toggleExpanded,
      indent,
      registerItem,
      unregisterItem,
    }),
    [
      indent,
      registerItem,
      resolvedExpandedIds,
      resolvedSelectedId,
      setSelectedId,
      toggleExpanded,
      unregisterItem,
    ],
  );

  const handleTreeContextMenuCapture = React.useCallback(
    (event: React.MouseEvent<HTMLUListElement>) => {
      onContextMenuCapture?.(event);

      if (event.defaultPrevented || !contextMenu) {
        return;
      }

      const target = event.target;

      if (!(target instanceof HTMLElement)) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      const itemButton = target.closest(
        '[data-slot="jb-tree-item-button"][data-value]',
      );

      if (!(itemButton instanceof HTMLElement)) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      const itemId = itemButton.dataset.value;

      if (!itemId) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      const node = itemRegistryRef.current.get(itemId);

      if (!node) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      const items = contextMenu(node) ?? [];

      if (items.length === 0) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      setContextMenuNode(node);
      setContextMenuItems(items);
    },
    [clearContextMenuState, contextMenu, onContextMenuCapture],
  );

  const treeList = (
    <ul
      data-slot="jb-tree"
      role="tree"
      className={cn(treeRootClassName, treeListClassName, className)}
      style={style}
      {...props}
      onContextMenuCapture={
        contextMenu ? handleTreeContextMenuCapture : onContextMenuCapture
      }
    >
      <TreeLevelContext.Provider value={1}>
        {children}
      </TreeLevelContext.Provider>
    </ul>
  );

  return (
    <TreeContext.Provider value={contextValue}>
      {contextMenu ? (
        <ContextMenu
          onOpenChange={(open) => {
            if (!open) {
              clearContextMenuState();
            }
          }}
        >
          <ContextMenuTrigger asChild>{treeList}</ContextMenuTrigger>
          {contextMenuNode && contextMenuItems.length ? (
            <ContextMenuContent>
              <TreeContextMenuEntries
                items={contextMenuItems}
                node={contextMenuNode}
              />
            </ContextMenuContent>
          ) : null}
        </ContextMenu>
      ) : (
        treeList
      )}
    </TreeContext.Provider>
  );
}

function TreeItem({
  className,
  value,
  label,
  icon,
  endContent,
  disabled = false,
  children,
  ...props
}: TreeItemProps) {
  const {
    selectedId,
    setSelectedId,
    expandedIds,
    toggleExpanded,
    indent,
    registerItem,
    unregisterItem,
  } = useTreeContext();
  const level = React.useContext(TreeLevelContext);

  const hasChildren = React.Children.count(children) > 0;
  const expanded = hasChildren ? expandedIds.has(value) : false;
  const selected = selectedId === value;
  const textLabel = getTreeItemLabel(label, value);
  const [keepGroupMounted, setKeepGroupMounted] = React.useState(expanded);
  const [groupExpanded, setGroupExpanded] = React.useState(expanded);
  const [isCollapsing, setIsCollapsing] = React.useState(false);
  const hasMountedRef = React.useRef(false);
  const collapseTimerRef = React.useRef<number | null>(null);
  const expandRafRef = React.useRef<number | null>(null);

  const rowPaddingLeft = 16 + (level - 1) * indent + Math.max(0, level - 2) * 2;

  const clearGroupAnimationHandles = React.useCallback(() => {
    if (collapseTimerRef.current !== null) {
      window.clearTimeout(collapseTimerRef.current);
      collapseTimerRef.current = null;
    }

    if (expandRafRef.current !== null) {
      window.cancelAnimationFrame(expandRafRef.current);
      expandRafRef.current = null;
    }
  }, []);

  React.useEffect(() => {
    return () => {
      clearGroupAnimationHandles();
    };
  }, [clearGroupAnimationHandles]);

  React.useEffect(() => {
    clearGroupAnimationHandles();

    if (!hasChildren) {
      setKeepGroupMounted(false);
      setGroupExpanded(false);
      setIsCollapsing(false);
      return;
    }

    if (!hasMountedRef.current) {
      hasMountedRef.current = true;
      setKeepGroupMounted(expanded);
      setGroupExpanded(expanded);
      setIsCollapsing(false);
      return;
    }

    if (expanded) {
      setKeepGroupMounted(true);
      setIsCollapsing(false);

      // Mount collapsed first, then expand on next frame so transition is visible.
      setGroupExpanded(false);
      expandRafRef.current = window.requestAnimationFrame(() => {
        expandRafRef.current = window.requestAnimationFrame(() => {
          setGroupExpanded(true);
          expandRafRef.current = null;
        });
      });

      return;
    }

    if (keepGroupMounted) {
      setGroupExpanded(false);
      setIsCollapsing(true);
      collapseTimerRef.current = window.setTimeout(() => {
        setKeepGroupMounted(false);
        setIsCollapsing(false);
        collapseTimerRef.current = null;
      }, GROUP_COLLAPSE_DURATION);
    }
  }, [clearGroupAnimationHandles, expanded, hasChildren, keepGroupMounted]);

  React.useEffect(() => {
    registerItem({
      id: value,
      value,
      label: textLabel,
      data: {
        label,
        icon,
        endContent,
        disabled,
      },
      disabled,
      expanded,
      hasChildren,
      level,
      selected,
    });

    return () => {
      unregisterItem(value);
    };
  }, [
    disabled,
    endContent,
    expanded,
    hasChildren,
    icon,
    label,
    level,
    registerItem,
    selected,
    textLabel,
    unregisterItem,
    value,
  ]);

  const handleSelect = React.useCallback(() => {
    if (disabled) {
      return;
    }

    setSelectedId(value);
  }, [disabled, setSelectedId, value]);

  const handleToggle = React.useCallback(
    (event: React.MouseEvent<HTMLButtonElement>) => {
      event.stopPropagation();

      if (disabled || !hasChildren) {
        return;
      }

      toggleExpanded(value);
    },
    [disabled, hasChildren, toggleExpanded, value],
  );

  const handleKeyDown = React.useCallback(
    (event: React.KeyboardEvent<HTMLDivElement>) => {
      if (disabled) {
        return;
      }

      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        handleSelect();
        return;
      }

      if (!hasChildren) {
        return;
      }

      if (event.key === 'ArrowRight' && !expanded) {
        event.preventDefault();
        toggleExpanded(value, true);
        return;
      }

      if (event.key === 'ArrowLeft' && expanded) {
        event.preventDefault();
        toggleExpanded(value, false);
      }
    },
    [disabled, expanded, handleSelect, hasChildren, toggleExpanded, value],
  );

  return (
    <li
      data-slot="jb-tree-item"
      data-value={value}
      className={treeItemClassName}
      {...props}
    >
      <div
        data-slot="jb-tree-item-button"
        data-value={value}
        data-has-children={hasChildren ? 'true' : undefined}
        data-selected={selected ? 'true' : undefined}
        data-disabled={disabled ? 'true' : undefined}
        data-expanded={hasChildren && expanded ? 'true' : undefined}
        data-level={level}
        role="treeitem"
        aria-level={level}
        aria-selected={selected}
        aria-expanded={hasChildren ? expanded : undefined}
        aria-disabled={disabled ? true : undefined}
        tabIndex={disabled ? -1 : 0}
        className={cn(treeItemButtonClassName, className)}
        style={{ paddingLeft: `${rowPaddingLeft}px` }}
        onClick={handleSelect}
        onDoubleClick={
          hasChildren && !disabled ? () => toggleExpanded(value) : undefined
        }
        onKeyDown={handleKeyDown}
      >
        {hasChildren ? (
          <button
            data-slot="jb-tree-item-disclosure"
            data-value={value}
            data-expanded={expanded ? 'true' : undefined}
            type="button"
            className={treeDisclosureClassName}
            aria-label={
              expanded ? `Collapse ${textLabel}` : `Expand ${textLabel}`
            }
            onClick={handleToggle}
            disabled={disabled}
          >
            {expanded ? (
              <ChevronDownIcon className="jb-tree-item-chevron" size={16} />
            ) : (
              <ChevronRightIcon className="jb-tree-item-chevron" size={16} />
            )}
          </button>
        ) : (
          <span
            data-slot="jb-tree-item-disclosure-placeholder"
            aria-hidden="true"
            className={treeDisclosurePlaceholderClassName}
          />
        )}

        <span
          data-slot="jb-tree-item-content"
          className={treeItemContentClassName}
        >
          {icon ? (
            <span
              data-slot="jb-tree-item-icon"
              className={treeItemIconClassName}
            >
              {icon}
            </span>
          ) : null}

          <span
            data-slot="jb-tree-item-label"
            className={treeItemLabelClassName}
          >
            {label}
          </span>

          {endContent ? (
            <span data-slot="jb-tree-item-end" className={treeItemEndClassName}>
              {endContent}
            </span>
          ) : null}
        </span>
      </div>

      {hasChildren && keepGroupMounted ? (
        <TreeLevelContext.Provider value={level + 1}>
          <div
            data-slot="jb-tree-group-motion"
            data-expanded={groupExpanded ? 'true' : undefined}
            data-collapsing={isCollapsing ? 'true' : undefined}
            className="jb-tree-group-motion"
            onTransitionEnd={() => {
              if (!groupExpanded) {
                setKeepGroupMounted(false);
                setIsCollapsing(false);
              }
            }}
          >
            <ul
              data-slot="jb-tree-group"
              role="group"
              aria-hidden={!expanded}
              className={treeGroupClassName}
            >
              {children}
            </ul>
          </div>
        </TreeLevelContext.Provider>
      ) : null}
    </li>
  );
}

export {
  DynamicTree,
  type DynamicTreeContextMenuIconName,
  type DynamicTreeContextMenuItem,
  type DynamicTreeContextMenuNode,
  type DynamicTreeItemData,
  type DynamicTreeProps,
} from './dynamic-tree';
export { Tree, TreeItem, type TreeItemProps, type TreeProps };

export default Tree;

'use client';

import * as React from 'react';
import { flushSync } from 'react-dom';

import {
  asyncDataLoaderFeature,
  type ItemInstance,
  type TreeDataLoader,
} from '@headless-tree/core';
import { useTree } from '@headless-tree/react';
import { cn } from '@/lib/utils';
import {
  AddIcon,
  CheckIcon,
  ChevronDownIcon,
  ChevronRightIcon,
  CloseIcon,
  CopyIcon,
  EditIcon,
  FilterIcon,
  RefreshIcon,
  SearchIcon,
  SettingsIcon,
  TrashIcon,
} from '@/components/jetbrains-ui/icons';
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuSub,
  ContextMenuSubContent,
  ContextMenuSubTrigger,
  ContextMenuTrigger,
} from '@/components/jetbrains-ui/context-menu';

export interface DynamicTreeItemData {
  label: string;
  icon?: React.ReactNode;
  endContent?: React.ReactNode;
  disabled?: boolean;
  isFolder?: boolean;
}

const dynamicTreeContextMenuIcons = {
  add: AddIcon,
  check: CheckIcon,
  close: CloseIcon,
  copy: CopyIcon,
  delete: TrashIcon,
  edit: EditIcon,
  filter: FilterIcon,
  refresh: RefreshIcon,
  search: SearchIcon,
  settings: SettingsIcon,
  trash: TrashIcon,
} as const;

export type DynamicTreeContextMenuIconName =
  keyof typeof dynamicTreeContextMenuIcons;

export interface DynamicTreeContextMenuNode {
  id: string;
  label: string;
  data: DynamicTreeItemData | null;
  item: ItemInstance<DynamicTreeItemData>;
  disabled: boolean;
  expanded: boolean;
  isFolder: boolean;
  level: number;
  loading: boolean;
  selected: boolean;
}

export interface DynamicTreeContextMenuItem {
  key: string;
  label?: React.ReactNode;
  text?: React.ReactNode;
  disabled?: boolean;
  separator?: boolean;
  separatorAfter?: boolean;
  iconName?: DynamicTreeContextMenuIconName;
  variant?: 'default' | 'destructive';
  onSelect?: (node: DynamicTreeContextMenuNode) => void;
  children?: DynamicTreeContextMenuItem[];
  items?: DynamicTreeContextMenuItem[];
}

export interface DynamicTreeProps
  extends Omit<
    React.ComponentPropsWithoutRef<'div'>,
    'children' | 'contextMenu'
  > {
  rootItemId: string;
  dataLoader: TreeDataLoader<DynamicTreeItemData>;
  treeLabel?: string;
  selectedId?: string | null;
  defaultSelectedId?: string | null;
  onSelectedIdChange?: (id: string) => void;
  expandedIds?: string[];
  defaultExpandedIds?: string[];
  onExpandedIdsChange?: (ids: string[]) => void;
  indent?: number;
  loadingLabel?: string;
  loadingEndContent?: React.ReactNode;
  contextMenu?: (
    node: DynamicTreeContextMenuNode,
  ) => DynamicTreeContextMenuItem[] | null | undefined;
}

type ItemRowProps = {
  indent: number;
  item: ItemInstance<DynamicTreeItemData>;
  rootItemId: string;
  selectedId: string | null;
  onSelect: (id: string) => void;
  loadingLabel: string;
  loadingEndContent: React.ReactNode;
};

type MenuEntriesProps = {
  items: DynamicTreeContextMenuItem[];
  node: DynamicTreeContextMenuNode;
};
const dynamicTreeRootClassName =
  'jb-tree block w-[244px] max-w-full box-border py-2 text-[13px] leading-4 font-medium';
const dynamicTreeItemClassName = 'jb-tree-item m-0 p-0';
const dynamicTreeItemButtonClassName =
  'jb-tree-item-button relative flex h-6 w-full min-w-0 cursor-default items-center gap-0.5 pr-4 select-none outline-none transition-[color,background-color,box-shadow] duration-150 ease-in-out';
const dynamicTreeDisclosureClassName =
  'jb-tree-item-disclosure inline-flex size-4 shrink-0 items-center justify-center';
const dynamicTreeDisclosurePlaceholderClassName =
  'jb-tree-item-disclosure-placeholder inline-flex size-4 shrink-0 items-center justify-center';
const dynamicTreeItemContentClassName =
  'jb-tree-item-content inline-flex h-5 min-w-0 flex-1 items-center gap-1.5';
const dynamicTreeItemIconClassName =
  'jb-tree-item-icon inline-flex size-4 shrink-0 items-center justify-center';
const dynamicTreeItemLabelClassName =
  'jb-tree-item-label min-w-0 overflow-hidden text-ellipsis whitespace-nowrap';
const dynamicTreeItemEndClassName =
  'jb-tree-item-end ml-auto pr-0.5 text-[13px] leading-4 font-medium';

function resolveContextMenuLabel(item: DynamicTreeContextMenuItem) {
  return item.label ?? item.text ?? item.key;
}

function resolveContextMenuChildren(item: DynamicTreeContextMenuItem) {
  return item.children ?? item.items ?? [];
}

function resolveContextMenuSeparator(item: DynamicTreeContextMenuItem) {
  return item.separatorAfter ?? item.separator ?? false;
}

function DynamicTreeContextMenuEntries({ items, node }: MenuEntriesProps) {
  return (
    <>
      {items.map((item) => {
        const label = resolveContextMenuLabel(item);
        const childItems = resolveContextMenuChildren(item);
        const IconComponent = item.iconName
          ? dynamicTreeContextMenuIcons[item.iconName]
          : null;
        const entry = childItems.length ? (
          <ContextMenuSub key={item.key}>
            <ContextMenuSubTrigger disabled={item.disabled}>
              {IconComponent ? (
                <IconComponent
                  aria-hidden="true"
                  className="size-4"
                  size={16}
                />
              ) : null}
              <span className="truncate">{label}</span>
            </ContextMenuSubTrigger>
            <ContextMenuSubContent>
              <DynamicTreeContextMenuEntries items={childItems} node={node} />
            </ContextMenuSubContent>
          </ContextMenuSub>
        ) : (
          <ContextMenuItem
            key={item.key}
            disabled={item.disabled}
            variant={item.variant}
            onSelect={() => item.onSelect?.(node)}
          >
            {IconComponent ? (
              <IconComponent aria-hidden="true" className="size-4" size={16} />
            ) : null}
            <span className="truncate">{label}</span>
          </ContextMenuItem>
        );

        if (!resolveContextMenuSeparator(item)) {
          return entry;
        }

        return (
          <React.Fragment key={`${item.key}-group`}>
            {entry}
            <ContextMenuSeparator />
          </React.Fragment>
        );
      })}
    </>
  );
}

function DynamicTreeItemRow({
  indent,
  item,
  rootItemId,
  selectedId,
  onSelect,
  loadingLabel,
  loadingEndContent,
}: ItemRowProps) {
  const itemProps = item.getProps() as React.ComponentPropsWithoutRef<'div'>;
  const resolvedProps = { ...itemProps };
  delete resolvedProps.onClick;
  delete resolvedProps.onDoubleClick;
  delete resolvedProps.onKeyDown;
  const resolvedClassName = resolvedProps.className;
  delete resolvedProps.className;
  const itemId = item.getId();
  const itemData = item.getItemData() as DynamicTreeItemData | null;
  const disabled = Boolean(itemData?.disabled);
  const selected = selectedId === itemId;
  const expanded = item.isExpanded();
  const folder = item.isFolder();
  const loading = item.isLoading();
  const level = item.getItemMeta().level;
  const label = itemData?.label ?? loadingLabel;
  const endContent = loading ? loadingEndContent : itemData?.endContent;
  const rowPaddingLeft = 16 + level * indent + Math.max(0, level - 1) * 2;

  const focusItem = React.useCallback(() => {
    item.setFocused();
  }, [item]);

  const toggleFolder = React.useCallback(() => {
    if (!folder) {
      return;
    }

    if (expanded) {
      item.collapse();
    } else {
      item.expand();
    }
  }, [expanded, folder, item]);

  const handleSelect = React.useCallback(() => {
    if (disabled) {
      return;
    }

    focusItem();
    onSelect(itemId);
  }, [disabled, focusItem, itemId, onSelect]);

  const handleKeyDown = React.useCallback(
    (event: React.KeyboardEvent<HTMLDivElement>) => {
      if (disabled) {
        return;
      }

      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        handleSelect();
        return;
      }

      if (event.key === 'ArrowRight') {
        event.preventDefault();

        if (folder && !expanded) {
          item.expand();
        } else {
          const next = item.getItemBelow();
          if (next) {
            next.setFocused();
            item.getTree().updateDomFocus();
          }
        }
        return;
      }

      if (event.key === 'ArrowLeft') {
        event.preventDefault();

        if (folder && expanded) {
          item.collapse();
          return;
        }

        const parent = item.getParent();
        if (parent && parent.getId() !== rootItemId) {
          parent.setFocused();
          item.getTree().updateDomFocus();
        }
        return;
      }

      if (event.key === 'ArrowDown') {
        event.preventDefault();
        const next = item.getItemBelow();
        if (next) {
          next.setFocused();
          item.getTree().updateDomFocus();
        }
        return;
      }

      if (event.key === 'ArrowUp') {
        event.preventDefault();
        const prev = item.getItemAbove();
        if (prev) {
          prev.setFocused();
          item.getTree().updateDomFocus();
        }
      }
    },
    [disabled, expanded, folder, handleSelect, item, rootItemId],
  );

  const handleDisclosureClick = React.useCallback(
    (event: React.MouseEvent<HTMLButtonElement>) => {
      event.stopPropagation();

      if (disabled) {
        return;
      }

      focusItem();
      toggleFolder();
    },
    [disabled, focusItem, toggleFolder],
  );

  return (
    <div
      data-slot="jb-tree-item"
      data-value={itemId}
      className={dynamicTreeItemClassName}
    >
      <div
        {...resolvedProps}
        data-slot="jb-tree-item-button"
        data-value={itemId}
        data-has-children={folder ? 'true' : undefined}
        data-selected={selected ? 'true' : undefined}
        data-disabled={disabled ? 'true' : undefined}
        data-expanded={folder && expanded ? 'true' : undefined}
        data-loading={loading ? 'true' : undefined}
        className={cn(dynamicTreeItemButtonClassName, resolvedClassName)}
        aria-selected={selected}
        aria-disabled={disabled ? true : undefined}
        aria-busy={loading ? true : undefined}
        tabIndex={disabled ? -1 : (resolvedProps.tabIndex ?? -1)}
        style={{ paddingLeft: `${rowPaddingLeft}px` }}
        onClick={handleSelect}
        onDoubleClick={
          folder && !disabled
            ? () => {
                focusItem();
                toggleFolder();
              }
            : undefined
        }
        onKeyDown={handleKeyDown}
      >
        {folder ? (
          <button
            data-slot="jb-tree-item-disclosure"
            data-value={itemId}
            data-expanded={expanded ? 'true' : undefined}
            type="button"
            className={dynamicTreeDisclosureClassName}
            aria-label={expanded ? `Collapse ${label}` : `Expand ${label}`}
            onClick={handleDisclosureClick}
            disabled={disabled}
          >
            {expanded ? (
              <ChevronDownIcon className="jb-tree-item-chevron" size={16} />
            ) : (
              <ChevronRightIcon className="jb-tree-item-chevron" size={16} />
            )}
          </button>
        ) : (
          <span
            data-slot="jb-tree-item-disclosure-placeholder"
            aria-hidden="true"
            className={dynamicTreeDisclosurePlaceholderClassName}
          />
        )}

        <span
          data-slot="jb-tree-item-content"
          className={dynamicTreeItemContentClassName}
        >
          {itemData?.icon ? (
            <span
              data-slot="jb-tree-item-icon"
              className={dynamicTreeItemIconClassName}
            >
              {itemData.icon}
            </span>
          ) : null}

          <span
            data-slot="jb-tree-item-label"
            className={dynamicTreeItemLabelClassName}
          >
            {label}
          </span>

          {endContent ? (
            <span
              data-slot="jb-tree-item-end"
              className={dynamicTreeItemEndClassName}
            >
              {endContent}
            </span>
          ) : null}
        </span>
      </div>
    </div>
  );
}

function DynamicTree({
  rootItemId,
  dataLoader,
  treeLabel = 'Tree',
  className,
  style,
  selectedId,
  defaultSelectedId = null,
  onSelectedIdChange,
  expandedIds,
  defaultExpandedIds = [],
  onExpandedIdsChange,
  indent = 16,
  loadingLabel = 'Loading...',
  loadingEndContent = '…',
  contextMenu,
  onContextMenuCapture,
  ...props
}: DynamicTreeProps) {
  const [uncontrolledSelectedId, setUncontrolledSelectedId] = React.useState<
    string | null
  >(defaultSelectedId);
  const [uncontrolledExpandedIds, setUncontrolledExpandedIds] =
    React.useState<string[]>(defaultExpandedIds);
  const [contextMenuNode, setContextMenuNode] =
    React.useState<DynamicTreeContextMenuNode | null>(null);
  const [contextMenuItems, setContextMenuItems] = React.useState<
    DynamicTreeContextMenuItem[]
  >([]);

  const resolvedSelectedId =
    selectedId !== undefined ? selectedId : uncontrolledSelectedId;
  const resolvedExpandedIds =
    expandedIds !== undefined ? expandedIds : uncontrolledExpandedIds;

  const setSelected = React.useCallback(
    (nextId: string) => {
      if (selectedId === undefined) {
        setUncontrolledSelectedId(nextId);
      }

      onSelectedIdChange?.(nextId);
    },
    [onSelectedIdChange, selectedId],
  );

  const setExpanded = React.useCallback(
    (updater: string[] | ((prev: string[]) => string[])) => {
      const nextIds =
        typeof updater === 'function' ? updater(resolvedExpandedIds) : updater;

      if (expandedIds === undefined) {
        setUncontrolledExpandedIds(nextIds);
      }

      onExpandedIdsChange?.(nextIds);
    },
    [expandedIds, onExpandedIdsChange, resolvedExpandedIds],
  );

  const tree = useTree<DynamicTreeItemData>({
    rootItemId,
    dataLoader,
    state: {
      expandedItems: resolvedExpandedIds,
    },
    setExpandedItems: setExpanded,
    isItemFolder: (item) => Boolean(item.getItemData()?.isFolder),
    getItemName: (item) => item.getItemData()?.label ?? item.getId(),
    createLoadingItemData: () => ({
      label: loadingLabel,
    }),
    features: [asyncDataLoaderFeature],
  });

  const containerProps = tree.getContainerProps(
    treeLabel,
  ) as React.ComponentPropsWithoutRef<'div'>;
  const items = tree.getItems();
  const itemMap = React.useMemo(
    () => new Map(items.map((item) => [item.getId(), item])),
    [items],
  );

  const createContextMenuNode = React.useCallback(
    (item: ItemInstance<DynamicTreeItemData>): DynamicTreeContextMenuNode => {
      const itemId = item.getId();
      const itemData = item.getItemData() as DynamicTreeItemData | null;

      return {
        id: itemId,
        label: itemData?.label ?? itemId,
        data: itemData,
        item,
        disabled: Boolean(itemData?.disabled),
        expanded: item.isExpanded(),
        isFolder: item.isFolder(),
        level: item.getItemMeta().level,
        loading: item.isLoading(),
        selected: resolvedSelectedId === itemId,
      };
    },
    [resolvedSelectedId],
  );

  const clearContextMenuState = React.useCallback(() => {
    setContextMenuNode(null);
    setContextMenuItems([]);
  }, []);

  const handleTreeContextMenuCapture = React.useCallback(
    (event: React.MouseEvent<HTMLDivElement>) => {
      onContextMenuCapture?.(event);

      if (event.defaultPrevented || !contextMenu) {
        return;
      }

      const target = event.target;

      if (!(target instanceof HTMLElement)) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      const itemButton = target.closest(
        '[data-slot="jb-tree-item-button"][data-value]',
      );

      if (!(itemButton instanceof HTMLElement)) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      const itemId = itemButton.dataset.value;

      if (!itemId) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      const item = itemMap.get(itemId);

      if (!item) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      const nextNode = createContextMenuNode(item);
      const nextItems = contextMenu(nextNode) ?? [];

      if (nextItems.length === 0) {
        event.preventDefault();
        clearContextMenuState();
        return;
      }

      flushSync(() => {
        setContextMenuNode(nextNode);
        setContextMenuItems(nextItems);
      });
    },
    [
      clearContextMenuState,
      contextMenu,
      createContextMenuNode,
      itemMap,
      onContextMenuCapture,
    ],
  );

  const treeContent = (
    <div
      {...containerProps}
      data-slot="jb-tree"
      className={cn(dynamicTreeRootClassName, className)}
      style={style}
      {...props}
      onContextMenuCapture={
        contextMenu ? handleTreeContextMenuCapture : onContextMenuCapture
      }
    >
      {items.map((item) => (
        <DynamicTreeItemRow
          key={item.getKey()}
          item={item}
          rootItemId={rootItemId}
          selectedId={resolvedSelectedId}
          onSelect={setSelected}
          indent={indent}
          loadingLabel={loadingLabel}
          loadingEndContent={loadingEndContent}
        />
      ))}
    </div>
  );

  if (!contextMenu) {
    return treeContent;
  }

  return (
    <ContextMenu
      onOpenChange={(open) => {
        if (!open) {
          clearContextMenuState();
        }
      }}
    >
      <ContextMenuTrigger asChild>{treeContent}</ContextMenuTrigger>
      {contextMenuNode && contextMenuItems.length ? (
        <ContextMenuContent>
          <DynamicTreeContextMenuEntries
            items={contextMenuItems}
            node={contextMenuNode}
          />
        </ContextMenuContent>
      ) : null}
    </ContextMenu>
  );
}

export { DynamicTree };

:root {
  --jb-tree-bg: transparent;
  --jb-tree-text: var(--jb-gray-1);
  --jb-tree-muted: var(--jb-gray-7);
  --jb-tree-icon: var(--jb-gray-6);
  --jb-tree-disclosure: var(--jb-gray-7);
  --jb-tree-disclosure-hover: var(--jb-gray-5);
  --jb-tree-item-hover-bg: var(--jb-gray-12);
  --jb-tree-item-active-bg: var(--jb-gray-11);
  --jb-tree-item-selected-bg: var(--jb-blue-11);
  --jb-tree-item-selected-text: var(--jb-gray-1);
  --jb-tree-focus-ring: var(--jb-blue-4);
  --jb-tree-focus-ring-offset: var(--jb-gray-14);
  --jb-tree-disabled-text: var(--jb-gray-8);
}

.dark {
  --jb-tree-bg: transparent;
  --jb-tree-text: var(--jb-gray-12);
  --jb-tree-muted: var(--jb-gray-7);
  --jb-tree-icon: var(--jb-gray-10);
  --jb-tree-disclosure: var(--jb-gray-10);
  --jb-tree-disclosure-hover: var(--jb-gray-12);
  --jb-tree-item-hover-bg: var(--jb-gray-3);
  --jb-tree-item-active-bg: var(--jb-gray-4);
  --jb-tree-item-selected-bg: var(--jb-blue-2);
  --jb-tree-item-selected-text: var(--jb-gray-12);
  --jb-tree-focus-ring: var(--jb-blue-6);
  --jb-tree-focus-ring-offset: var(--jb-gray-2);
  --jb-tree-disabled-text: var(--jb-gray-7);
}

.jb-tree {
  background: var(--jb-tree-bg);
  color: var(--jb-tree-text);
  font-family: var(--jb-font-sans), sans-serif;
}

.jb-tree-group-motion {
  display: grid;
  grid-template-rows: 0fr;
  min-height: 0;
  opacity: 0;
  transform: translateY(-2px);
  pointer-events: none;
  transition:
    grid-template-rows 170ms var(--jb-ease-out),
    opacity 140ms var(--jb-ease-out),
    transform 170ms var(--jb-ease-out);
}

.jb-tree-group-motion[data-expanded='true'] {
  grid-template-rows: 1fr;
  opacity: 1;
  transform: translateY(0);
  pointer-events: auto;
}

.jb-tree-group-motion .jb-tree-group {
  min-height: 0;
  overflow: hidden;
}

.jb-tree-item-button {
  position: relative;
  color: var(--jb-tree-text);
  box-sizing: border-box;
}

.jb-tree-item-button::before {
  content: '';
  position: absolute;
  inset: 0 12px;
  border-radius: 4px;
  background: transparent;
  transition:
    background-color var(--jb-transition-fast) ease-in-out,
    box-shadow var(--jb-transition-fast) ease-in-out;
}

.jb-tree-item-button > * {
  position: relative;
  z-index: 1;
}

.jb-tree-item-button:hover:not([data-disabled='true']) {
  background: transparent;
}

.jb-tree-item-button:hover:not([data-disabled='true'])::before {
  background: var(--jb-tree-item-hover-bg);
}

.jb-tree-item-button:active:not([data-disabled='true']) {
  background: transparent;
}

.jb-tree-item-button:active:not([data-disabled='true'])::before {
  background: var(--jb-tree-item-active-bg);
}

.jb-tree-item-button[data-selected='true'] {
  background: transparent;
  color: var(--jb-tree-item-selected-text);
}

.jb-tree-item-button[data-selected='true']::before {
  background: var(--jb-tree-item-selected-bg);
}

.jb-tree-item-button:focus-visible::before {
  box-shadow:
    0 0 0 1px var(--jb-tree-focus-ring-offset),
    0 0 0 3px var(--jb-tree-focus-ring);
}

.jb-tree-item-button[data-disabled='true'] {
  color: var(--jb-tree-disabled-text);
  cursor: not-allowed;
}

.jb-tree-item-disclosure {
  border: 0;
  background: transparent;
  padding: 0;
  color: var(--jb-tree-disclosure);
  outline: none;
}

.jb-tree-item-disclosure:hover:not(:disabled) {
  color: var(--jb-tree-disclosure-hover);
}

.jb-tree-item-disclosure:disabled {
  cursor: not-allowed;
}

.jb-tree-item-chevron {
  width: 16px;
  height: 16px;
  transform: scale(0.78);
  transform-origin: center;
}

.jb-tree-item-icon {
  color: var(--jb-tree-icon);
}

.jb-tree-item-button[data-selected='true'] .jb-tree-item-icon,
.jb-tree-item-button[data-selected='true'] .jb-tree-item-disclosure {
  color: currentColor;
}

.jb-tree-item-icon > svg {
  width: 16px;
  height: 16px;
}

.jb-tree-item-end {
  color: var(--jb-tree-muted);
}
